mat2 rotate2D(float angle) { float s = sin(angle); float c = cos(angle); return mat2(c, -s, s, c); }

mat3 rotateX(float a) { float s = sin(a); float c = cos(a); return mat3(1,0,0, 0,c,-s, 0,s,c); }

mat3 rotateY(float a) { float s = sin(a); float c = cos(a); return mat3(c,0,s, 0,1,0, -s,0,c); }

mat3 rotateZ(float a) { float s = sin(a); float c = cos(a); return mat3(c,-s,0, s,c,0, 0,0,1); }

float easeInOut(float t) { return t * t * (3.0 - 2.0 * t); }

float easeInQuad(float t) { return t * t; }

float easeOutQuad(float t) { return t * (2.0 - t); }

float hash11(float p) { p = fract(p * 0.1031); p *= p + 33.33; p *= p + p; return fract(p); }

float hash21(vec2 p) { vec3 p3 = fract(vec3(p.xyx) * 0.1031); p3 += dot(p3, p3.yzx + 33.33); return fract((p3.x + p3.y) * p3.z); }

vec2 hash22(vec2 p) { vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973)); p3 += dot(p3, p3.yzx + 33.33); return fract((p3.xx + p3.yz) * p3.zy); }
